var e=[{id:`L2_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`크윽……!`,JPN:`くうっ……！`,ENG:`Kgh...!`,TWN:`唔呃……！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`한심하네. 고작 잡졸들을 상대로 벌써 만신창이가 되다니.`,JPN:`情けないわね。雑魚相手にもうボロボロじゃない。`,ENG:`Pathetic. Already exhausted after taking care of a few grunts.`,TWN:`真令人失望，才對付幾個小嘍囉你就已經這麼吃力。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`고작 그런 수준으로 나한테 복수하겠다고 날뛴 거야?`,JPN:`その程度で私に復讐しようとしたわけ？`,ENG:`You think you can get back at me with that?`,TWN:`就憑你這個水準，還想找我報什麼仇？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L7_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`처음엔 신의 후손이니 환상종의 혈통이니 해서 살짝 기대했는데.`,JPN:`最初は神の子孫だの、幻想種の血統だのってちょっと期待したけど。`,ENG:`I was kinda hoping for a good fight as you're the descendant of god or some bloodline of a Bygone.`,TWN:`我原本還有點期待，想說你們是神的後裔，又是什麼夢幻類的血脈之類的。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`너 같이 쓸모도 없는 녀석을 구하려고 자기 목숨을 버리는 멍청한 년이 이끄는 군대라니.`,JPN:`お前のような役立たずを助けるために自分の命を捨てるバカが率いる軍隊とはね。`,ENG:`But to find an army led by a stupid girl who risked her life to save a useless girl like you.`,TWN:`結果沒想到，竟然一個是因為要救你這個沒用的東西，而犧牲自己性命的蠢女人所帶領的軍隊。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`이런 걸 자연도태라고 부르지?`,JPN:`これを自然選択と言うのかしら？`,ENG:`Isn't that what you call natural selection?`,TWN:`這種就叫自然淘汰吧？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`narration`,speaker:null,text:{KOREA:`미래를 알 수 없어도 상관없다.`,JPN:`未来がわからなくても構わない。`,ENG:`Not knowing the future does not matter.`,TWN:`無法得知未來也無所謂。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L16_1`,type:`narration`,speaker:null,text:{KOREA:`이 선택만큼은…… 절대로 후회하지 않을 테니까.`,JPN:`この選択だけは……絶対に後悔しないから。`,ENG:`The choice I make now... I will never regret.`,TWN:`因為這個選擇……我絕對不會後悔。`},stage:{bg:`BLACK`,slots:{L:null,C:null,R:null}}},{id:`L18_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`내가 검을 휘두르는 건, 복수를 위해서가 아니다.`,JPN:`私が刀を振るうのは、復讐のためではない。`,ENG:`I wield this sword, not for revenge.`,TWN:`我揮劍不是因為要報仇。`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:null,R:null}}},{id:`L20_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`뭐……?`,JPN:`なに……？`,ENG:`What...?`,TWN:`什麼……？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`그런 대답은 예정에 없었……`,JPN:`そんな答えは予定になか……`,ENG:`I didn't expect that ans–`,TWN:`這回答不在預言內……`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`크윽?!`,JPN:`くうっ！？`,ENG:`Argh?!`,TWN:`呃？！`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`LENORE_UNION_NULL_NULL`,text:{KOREA:`공격? 아무것도 안 보였는데……? `,JPN:`攻撃？　 何も見えなかったのに……？ `,ENG:`I got hit? But I didn't see anything...!`,TWN:`攻擊？我什麼都看不到……？`},stage:{bg:`NANAHARA_SEAL`,slots:{L:null,C:{char_id:`LENORE_UNION_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`CHIFUYU_NANA_CA_NULL`,text:{KOREA:`지킨다는 것의 의미와 그 가치를……`,JPN:`守るということの意味と価値を……`,ENG:`One who has killed to obtain the power of god...`,TWN:`守護的意義和價值……`},stage:{bg:`NANAHARA2_04`,slots:{L:null,C:null,R:null}}},{id:`L29_1`,type:`dialog`,speaker:`CHIFUYU_NANA_CA_NULL`,text:{KOREA:`살생을 통해 신의 힘을 찾아온 너희들은 영원히 깨닫지 못하겠지.`,JPN:`殺生を通して神の力を探したお前らは永遠に気づけないだろう。`,ENG:`Thou shall never learn the true meaning and value of protecting...`,TWN:`靠殺戮得到神力的你們永遠都不會明白吧？`},stage:{bg:`NANAHARA2_04`,slots:{L:null,C:null,R:null}}}];export{e as default};